function track(kind: WorkshopUltimateTrack['valueKind'], rows: readonly (readonly [number, number])[]) {
  return {
    valueKind: kind,
    milestones: rows.map(([value, marginalStones], i) => ({
      value,
      marginalStones: i === 0 ? 0 : marginalStones,
    })),
  } satisfies WorkshopUltimateTrack
}

